#include<bits/stdc++.h>
using namespace std;

bool a[1101][1101];
int c[105];
int num,n,k,m;
bool check(int s){
	for(int i=1;i<=s;i++){
		if(a[i][s]&&c[i]==c[s]){
			return false;
		}
	}
	return true;
}
void dfs(int x){
	if(x>n){
		num++;
		return;
	}
	for(int i=1;i<=m;i++){
		c[x]=i;
		if(check(x)){
			dfs(x+1);
		}else{
			c[x]=0;
		}
	}
}
int main() {
	cin >> n >>k>> m;
	for (int i = 0; i < k; i++) {
		int x, y;
		cin >> x >> y;
		a[x][y] = 1;
		a[y][x] = 1;
	}
	dfs(1);
	cout<<num;
	return 0;
}
